#include <stdio.h>

int main() {
    int T, x;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &x) != 1) return 0;
        printf("%d\n", 2000 - x);
    }
    return 0;
}

